// Problem: easy to mix up different IDs that are all u64
// user_service.get(order_id) compiles but is a bug!

// Solution: newtypes
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
struct UserId(u64);

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
struct OrderId(u64);

#[derive(Debug, Clone, PartialEq)]
struct EmailAddress(String);

impl EmailAddress {
    fn new(email: &str) -> Result<Self, String> {
        if email.contains('@') && email.contains('.') {
            Ok(EmailAddress(email.to_lowercase()))
        } else {
            Err(format!("Invalid email: {}", email))
        }
    }

    fn as_str(&self) -> &str {
        &self.0
    }
}

impl std::fmt::Display for EmailAddress {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "{}", self.0)
    }
}

fn send_email(to: &EmailAddress, subject: &str) {
    println!("Sending '{}' to {}", subject, to);
}

fn get_user(id: UserId) -> String {
    format!("User #{}", id.0)
}

fn main() {
    let user_id = UserId(42);
    let _order_id = OrderId(42);

    // get_user(order_id);  // Compile error! Expected UserId, got OrderId
    println!("{}", get_user(user_id));

    let email = EmailAddress::new("Alice@Example.com").unwrap();
    send_email(&email, "Hello!");
    // Stored as lowercase: alice@example.com
    println!("Email: {}", email);
}
